SELECT COUNT(*)::bigint AS cnt
FROM leads_client
WHERE (COALESCE(published_at, synced_at) AT TIME ZONE 'UTC')::date = (timezone('UTC', now()))::date;

SELECT COUNT(*)::bigint AS cnt
FROM leads_client
WHERE COALESCE(published_at, synced_at) >= (timezone('UTC', now()) - interval '7 days');

SELECT ROUND(AVG(price_usd)::numeric, 2) AS avg_usd
FROM leads_client
WHERE price_usd IS NOT NULL;

SELECT ROUND(AVG(price_gel)::numeric, 2) AS avg_gel
FROM leads_client
WHERE price_gel IS NOT NULL;
